<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted } from "vue";
import { Motion } from "motion-v";

const svgRef = ref<SVGSVGElement | null>(null);

// ── Mouse tracking ─────────────────────────────────────────────
let targetPX = 0;
let targetPY = 0;
const pointerX = ref(0);
const pointerY = ref(0);

function handleMouseMove(e: MouseEvent) {
	const el = svgRef.value;

	if (!el) return;
	const rect = el.getBoundingClientRect();

	targetPX = e.clientX - rect.left - rect.width / 2;
	targetPY = e.clientY - rect.top - rect.height / 2;
}

function handleMouseLeave() {
	targetPX = 0;
	targetPY = 0;
}

// Independent parallax — mixed signs give each card its own "depth layer":
// positive dx/dy → moves with mouse, negative → moves against mouse
const CARD_PARALLAX = [
	{ dx: -0.06, dy: 0.04 }, // green pill    — opposite-x, with-y
	{ dx: 0.07, dy: -0.05 }, // white pill    — with-x, opposite-y
	{ dx: -0.04, dy: -0.06 }, // blue pill    — opposite on both axes
	{ dx: 0.05, dy: 0.06 }, // yellow circle  — with-x, with-y
];

const cardStyles = computed(() =>
	CARD_PARALLAX.map(({ dx, dy }) => ({
		transform: `translate(${(pointerX.value * dx).toFixed(2)}px, ${(pointerY.value * dy).toFixed(2)}px)`,
	})),
);

// ── Spring smoothing loop ───────────────────────────────────────
let rafId = 0;

function tick() {
	pointerX.value += (targetPX - pointerX.value) * 0.1;
	pointerY.value += (targetPY - pointerY.value) * 0.1;
	rafId = requestAnimationFrame(tick);
}

onMounted(() => {
	if (!import.meta.client) return;
	rafId = requestAnimationFrame(tick);
});

onUnmounted(() => {
	cancelAnimationFrame(rafId);
});
</script>

